118→        /// <summary>
119→        /// FEnet 요청하기
120→        /// </summary>
121→        /// <param name="timeout">응답 제한시간(밀리초)</param>
122→        /// <param name="request">FEnet 요청</param>
123→        /// <returns>FEnet 응답</returns>
124→        public FEnetResponse Request(int timeout, FEnetRequest request)
125→        {
126→            Channel channel = (Channel as Channel) ?? (Channel as ChannelProvider)?.PrimaryChannel;
127→
128→            if (channel == null)
129→                throw new ArgumentNullException(nameof(Channel));
130→
131→            byte[] requestMessage;
132→            FEnetRequestLog requestLog;
133→            FEnetResponse result;
134→            List<byte> buffer = new List<byte>();
135→
136→            lock (lockSerialize)
137→            {
138→                request = (FEnetRequest)request.Clone();
139→                if (request.InvokeID == null)
140→                    request.InvokeID = invokeID++;
141→                if (request.UseHexBitIndex == null)
142→                    request.UseHexBitIndex = UseHexBitIndex;
143→                requestMessage = request.Serialize(CompanyID, UseChecksum).ToArray();
144→            }
145→
146→            try
147→            {
148→                if (responseWaitHandles.TryGetValue(request.InvokeID.Value, out var oldHandle))
149→                    oldHandle.WaitOne(timeout);
150→
151→                ResponseWaitHandle responseWaitHandle;
152→                lock (responseWaitHandles)
153→                    responseWaitHandle = responseWaitHandles[request.InvokeID.Value] = new ResponseWaitHandle(buffer, request, timeout);
154→
155→                channel.Write(requestMessage);
156→                requestLog = new FEnetRequestLog(channel, request, requestMessage);
157→                channel?.Logger?.Log(requestLog);
158→
159→                RunReceive(channel);
160→
161→                responseWaitHandle.WaitOne(timeout);
162→
163→                result = responseWaitHandle.Response;
164→                lock (responseWaitHandles)
165→                    responseWaitHandles.Remove(request.InvokeID.Value);
166→                if (result == null)
167→                    result = new FEnetCommErrorResponse(FEnetCommErrorCode.ResponseTimeout, new byte[0], request, 0, 0);
168→            }
169→            catch (Exception ex)
170→            {
171→                channel?.Logger?.Log(new ChannelErrorLog(channel, ex.InnerException ?? ex));
172→                throw ex.InnerException ?? ex;
173→            }
174→
175→            if (result is FEnetCommErrorResponse commErrorResponse)
176→            {
177→                var ex = new RequestException<FEnetCommErrorCode>(commErrorResponse.ErrorCode, commErrorResponse.ReceivedBytes, commErrorResponse.Request);
178→                channel?.Logger?.Log(new ChannelErrorLog(channel, ex));
179→                throw ex;
180→            }
181→
182→            if (result is FEnetNAKResponse exceptionResponse)
183→            {
184→                channel?.Logger?.Log(new FEnetNAKLog(channel, exceptionResponse, buffer.ToArray(), requestLog));
185→                if (ThrowsExceptionFromNAK)
186→                    throw new FEnetNAKException(exceptionResponse.NAKCode, exceptionResponse.NAKCodeValue);
187→            }
188→            else
189→                channel?.Logger?.Log(new FEnetResponseLog(channel, result, result is FEnetNAKResponse ? null : buffer.ToArray(), requestLog));
190→
191→            return result;
192→        }
